#!/usr/bin/env python3
#requirements:
#requests
#psutil
#
import subprocess
import sys
import re
import os
import tempfile
import time
import shutil
from datetime import datetime

# Note: wmill will be imported inside get_windmill_variable function
# This allows it to work even if wmill is not available at import time

# Embedded PowerShell script content
POWERSHELL_SCRIPT = r'''<# wmill: 
{
    "schema": {
        "type": "object",
        "properties": {
            "tenantid": {
                "title": "Azure Tenant ID",
                "type": "string",
                "default": "30759d1a-f690-4205-9005-7d871a4f484c"
            },
            "subscription_ids": {
                "title": "Subscription IDs (comma-separated)",
                "type": "string",
                "default": "97c4ecbb-e54d-4bc1-bfc5-32cc73c03bee,d4f0b259-e982-48f7-9953-fb07adec333c"
            },
            "client_id": {
                "title": "Service Principal Client ID",
                "type": "string"
            },
            "client_secret": {
                "title": "Service Principal Client Secret",
                "type": "string",
                "format": "password"
            }
        },
        "required": ["tenantid", "subscription_ids", "client_id", "client_secret"]
    }
}
#>

param(
    [Parameter(Mandatory=$true)]
    [string]$tenantid = '30759d1a-f690-4205-9005-7d871a4f484c',
    [Parameter(Mandatory=$true)]
    [string]$subscription_ids = '97c4ecbb-e54d-4bc1-bfc5-32cc73c03bee,d4f0b259-e982-48f7-9953-fb07adec333c',
    [Parameter(Mandatory=$true)]
    [string]$client_id,
    [Parameter(Mandatory=$true)]
    [string]$client_secret
)

# Suppress error output from unshare/sigprocmask (Windmill sandbox limitation)
# Set error handling to continue on errors (we'll handle them explicitly)
$ErrorActionPreference = 'Continue'
$PSDefaultParameterValues['*:ErrorAction'] = 'Continue'

# Store original error action preference
$originalErrorActionPreference = $ErrorActionPreference

# Global flag to track if script succeeded
$script:ScriptSuccess = $false

# Note: sigprocmask errors are filtered by the Python wrapper
# We don't need a trap handler here - let try-catch blocks handle errors normally

Write-Host "========================================"
Write-Host " Azure Resource Inventory (ARI) Script "
Write-Host "========================================"
Write-Host "Tenant ID: $tenantid"
Write-Host "Target Subscriptions: $subscription_ids"
Write-Host ""

# Ensure TLS1.2 for PSGallery
[Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12

# Install system dependencies for ImportExcel (required for Excel file generation)
Write-Host "Installing system dependencies for ImportExcel..."
try {
    # Try to install libgdiplus and libc6-dev if not already installed
    $null = bash -c "apt-get update -qq && apt-get install -y --no-install-recommends libgdiplus libc6-dev 2>&1" 2>&1
    Write-Host "  ✓ System dependencies installed (or already present)"
} catch {
    Write-Host "  ⚠ Could not install system dependencies (may already be installed): $_"
}

# Install required modules for current user (Windmill-safe)
# Match official Microsoft ARI example: Install AzureResourceInventory, Az.Accounts, and ImportExcel
Write-Host "Installing PowerShell modules..."
try {
    # Install PowerShellGet first (required for other modules)
    Install-Module PowerShellGet -Force -Scope CurrentUser -AllowClobber -ErrorAction SilentlyContinue | Out-Null

    # Install full Az module (like GitLab does) - this includes Az.Accounts
    # GitLab uses full Az module, not just Az.Accounts
    Write-Host "  Installing Az module..."
    Install-Module Az -Force -Scope CurrentUser -AllowClobber -ErrorAction Stop | Out-Null
    Write-Host "  ✓ Az module installed"

    # Install AzureResourceInventory (required for ARI)
    Write-Host "  Installing AzureResourceInventory..."
    $existingARI = Get-Module -ListAvailable -Name AzureResourceInventory | Sort-Object Version -Descending | Select-Object -First 1
    if ($existingARI) {
        Write-Host "  Found existing AzureResourceInventory version $($existingARI.Version)"
    }
    Install-Module AzureResourceInventory -Force -Scope CurrentUser -AllowClobber -ErrorAction Stop | Out-Null
    Write-Host "  ✓ AzureResourceInventory installed"

    # Install ImportExcel (required for Excel file generation) - match official example
    Write-Host "  Installing ImportExcel..."
    Install-Module ImportExcel -Force -Scope CurrentUser -AllowClobber -ErrorAction Stop | Out-Null
    Write-Host "  ✓ ImportExcel installed"

    Write-Host "✓ Modules installed successfully"
} catch {
    Write-Host "⚠ Module installation warning: $_"
    # Try to continue - modules might already be installed
}

# Import modules - match GitLab approach: Import full Az module
Write-Host "Importing modules..."
try {
    # Match GitLab: Import full Az module (includes Az.Accounts)
    Write-Host "  Importing Az module..."
    Import-Module Az -Force -ErrorAction Stop | Out-Null
    Write-Host "  ✓ Az module imported"

    # Import AzureResourceInventory (required for Invoke-ARI)
    Write-Host "  Importing AzureResourceInventory..."
    Import-Module AzureResourceInventory -Force -ErrorAction Stop | Out-Null
    Write-Host "  ✓ AzureResourceInventory imported"

    Write-Host "✓ All required modules imported successfully"

} catch {
    $errorMsg = $_.Exception.Message
    Write-Host "✗ Failed to import modules: $errorMsg"
    throw
}

# Azure Authentication using Service Principal
Write-Host "`nAuthenticating to Azure using Service Principal..."
try {
    # Validate required parameters
    if ([string]::IsNullOrWhiteSpace($client_id)) {
        throw "Service Principal Client ID is required"
    }
    if ([string]::IsNullOrWhiteSpace($client_secret)) {
        throw "Service Principal Client Secret is required"
    }

    Write-Host "Connecting with Service Principal (Client ID: $client_id)..."
    $secureSecret = ConvertTo-SecureString $client_secret -AsPlainText -Force
    $credential = New-Object System.Management.Automation.PSCredential($client_id, $secureSecret)
    Connect-AzAccount -ServicePrincipal -TenantId $tenantid -Credential $credential -ErrorAction Stop | Out-Null
    Write-Host "✓ Service Principal authentication successful"
} catch {
    Write-Host "✗ Azure authentication failed: $_"
    throw
}

# Parse subscription IDs
$ids = $subscription_ids -split ',' | ForEach-Object { $_.Trim() } | Where-Object { $_ }
Write-Host "`nTarget Subscription IDs:"
foreach ($id in $ids) {
    Write-Host "  - $id"
}

# Run ARI with error handling
Write-Host "`nRunning Azure Resource Inventory..."
Write-Host "This may take several minutes..."

$ariSuccess = $false
$realErrors = @()

try {
    # CRITICAL: Change to /root directory before running ARI
    # Windmill runs PowerShell from a temp directory, but ARI creates files in the current working directory
    # By changing to /root, we ensure files are created in a known location
    Write-Host "Current working directory: $(Get-Location)"
    Write-Host "Changing to /root directory..."
    Set-Location /root
    Write-Host "New working directory: $(Get-Location)"

    # Ensure output directory exists (ARI creates files in current directory by default)
    $ariOutputDir = "/root/AzureResourceInventory"
    if (-not (Test-Path $ariOutputDir)) {
        New-Item -ItemType Directory -Path $ariOutputDir -Force | Out-Null
        Write-Host "Created output directory: $ariOutputDir"
    }

    # Run ARI - match official Microsoft ARI example approach exactly
    # Reference: https://github.com/microsoft/ARI/blob/main/azure-pipelines/ari-inventory.yml
    Write-Host "Preparing ARI parameters..."
    $ariParams = @{}

    # Add TenantID
    $ariParams.Add("TenantID", $tenantid)

    # Add SubscriptionID if provided
    if ($ids -and $ids.Count -gt 0) {
        $ariParams.Add("SubscriptionID", $ids)
    }

    # Add SkipDiagram parameter to skip diagram generation
    # This prevents ARI from creating Draw.io diagrams and DiagramCache files
    # Diagrams are not needed in Windmill environment and save processing time
    $ariParams.Add("SkipDiagram", $true)

    # CRITICAL: Use -Lite mode to speed up processing and avoid Windmill timeout
    # -Lite mode reduces processing time by skipping some detailed analysis
    # This should help complete within Windmill's ~3-4 minute timeout limit
    # Trade-off: May reduce some report detail, but ensures completion
    $ariParams.Add("Lite", $true)
    Write-Host "  Using -Lite mode to speed up processing (may reduce report detail)"

    # CRITICAL: Set ReportDir to explicitly control where ARI saves the Excel file
    # Without this, ARI might save to default location ($HOME/AzureResourceInventory or current directory)
    $ariParams.Add("ReportDir", $ariOutputDir)
    Write-Host "  Report directory: $ariOutputDir"

    # Add ReportName to control output filename (match official example)
    $reportName = "AzureResourceInventory_Report_$(Get-Date -Format 'yyyy-MM-dd_HH_mm')"
    $ariParams.Add("ReportName", $reportName)
    Write-Host "  Report name: $reportName"

    Write-Host "Running Invoke-ARI with parameters:"
    foreach ($key in $ariParams.Keys) {
        if ($key -eq 'SubscriptionID') {
            Write-Host "  $key = $($ids -join ',')"
        } else {
            Write-Host "  $key = $($ariParams[$key])"
        }
    }

    # IMPORTANT: Reset ErrorActionPreference to Continue (not SilentlyContinue) before calling ARI
    # This ensures errors are visible but don't stop execution
    $ErrorActionPreference = 'Continue'

    # Enable Debug to see detailed output (like GitLab shows "Starting to Build Excel Report")
    # This will help us see if Excel building phase starts
    $ariParams.Add("Debug", $true)  # Enable debug to see Excel building phase

    # Run ARI - capture output to see if processing phase runs
    # Use 2>&1 to capture both stdout and stderr so we can see any errors
    Write-Host "`nExecuting Invoke-ARI..."
    Write-Host "Note: Processing phase should start after Extraction Phase Finished"
    Write-Host "If you don't see 'Processing Phase Finished', check for errors below..."
    Write-Host ""

    try {
        # Capture output to see what's happening
        $ariOutput = Invoke-ARI @ariParams 2>&1

        # Write all output so we can see what happened
        # Also capture file path from ARI debug output
        $excelFilePathFromDebug = $null
        $foundFilePaths = @()
        foreach ($line in $ariOutput) {
            if ($line -is [System.Management.Automation.ErrorRecord]) {
                $errMsg = $line.ToString()
                # Don't suppress errors - we need to see what's preventing processing
                Write-Host "ERROR: $errMsg" -ForegroundColor Red
            } else {
                Write-Host $line
                # Look for the debug line that shows the Excel file path
                # Format: "DEBUG: ... - Excel file: /path/to/file.xlsx"
                if ($line -match 'DEBUG.*Excel file:\s*(.+\.xlsx)') {
                    $excelFilePathFromDebug = $matches[1]
                    Write-Host "`n[FOUND] Excel file path from ARI debug output: $excelFilePathFromDebug" -ForegroundColor Green
                }
                # Also look for other file path hints
                if ($line -match '\.xlsx|Excel.*file|Report.*saved|File.*created|saved.*to|created.*at') {
                    $foundFilePaths += $line
                }
            }
        }

        # If we found the file path in debug output, verify it exists IMMEDIATELY
        # This is critical - check right away before any cleanup happens
        if ($excelFilePathFromDebug) {
            Write-Host "`n[IMMEDIATE CHECK] Checking file from debug output: $excelFilePathFromDebug"
            if (Test-Path $excelFilePathFromDebug) {
                Write-Host "`n✓ VERIFIED: Excel file exists at: $excelFilePathFromDebug" -ForegroundColor Green
                $fileInfo = Get-Item $excelFilePathFromDebug
                Write-Host "  File size: $([math]::Round($fileInfo.Length/1MB, 2)) MB"
                Write-Host "  Last modified: $($fileInfo.LastWriteTime)"
                Write-Host "EXCEL_FILE_PATH=$excelFilePathFromDebug"

                # Store the file path in a script-level variable so we can access it later
                $script:FoundExcelFilePath = $excelFilePathFromDebug

                # Also copy to a safe location immediately to prevent loss
                $safeCopyPath = "/root/AzureResourceInventory_SAFE_COPY.xlsx"
                try {
                    Copy-Item -Path $excelFilePathFromDebug -Destination $safeCopyPath -Force -ErrorAction Stop
                    Write-Host "  ✓ Copied to safe location: $safeCopyPath" -ForegroundColor Green
                    Write-Host "SAFE_COPY_PATH=$safeCopyPath"
                } catch {
                    Write-Host "  ⚠ Failed to create safe copy: $_" -ForegroundColor Yellow
                }
            } else {
                Write-Host "`n⚠ WARNING: ARI reported file path but file doesn't exist: $excelFilePathFromDebug" -ForegroundColor Yellow
                Write-Host "  This suggests the file was deleted or never created."
            }
        }

        # If we found file path hints in output, log them
        if ($foundFilePaths.Count -gt 0) {
            Write-Host "`n[DEBUG] Found potential file path hints in ARI output:"
            foreach ($hint in $foundFilePaths) {
                Write-Host "  - $hint"
            }
        }

        Write-Host "`n✓ Invoke-ARI completed"
        Write-Host "[DEBUG] ARI output captured, checking for processing phase completion..."

        # Check if processing phase completed
        $processingFinished = $ariOutput | Where-Object { $_ -match 'Processing Phase Finished' }
        if (-not $processingFinished) {
            Write-Host "`n⚠ WARNING: Processing Phase Finished not detected!"
            Write-Host "  This means the Excel file was NOT generated."
            Write-Host "  Checking for errors that prevented processing..."

            $errors = $ariOutput | Where-Object { $_ -is [System.Management.Automation.ErrorRecord] }
            if ($errors) {
                Write-Host "  Found errors during execution:"
                foreach ($err in $errors) {
                    $errMsg = $err.ToString()
                    if ($errMsg -notmatch 'sigprocmask|unshare|Auto-fitting|Cannot Autosize') {
                        Write-Host "    - $errMsg" -ForegroundColor Red
                    }
                }
            } else {
                Write-Host "  No errors detected, but processing phase didn't complete."
                Write-Host "  This might be a Windmill sandbox limitation."
            }
        } else {
            Write-Host "`n✓ Processing Phase Finished detected - Excel file should be generated"

            # CRITICAL: Check for file IMMEDIATELY after processing finishes
            # Don't wait - check right away in case file gets deleted
            Write-Host "  [IMMEDIATE CHECK] Searching for Excel file RIGHT NOW (before any delays)..."
            $immediateCheck = Get-ChildItem -Path $ariOutputDir -Filter "*.xlsx" -ErrorAction SilentlyContinue -Recurse
            if ($immediateCheck) {
                Write-Host "  [IMMEDIATE CHECK] ✓ Found Excel file(s) immediately:"
                foreach ($file in $immediateCheck) {
                    Write-Host "    - $($file.FullName) ($([math]::Round($file.Length/1MB, 2)) MB)"
                }
            } else {
                Write-Host "  [IMMEDIATE CHECK] ⚠ No Excel files found immediately after Processing Phase Finished"
            }

            # Also check ReportCache directory - ARI might store files there temporarily
            $reportCacheDir = Join-Path $ariOutputDir "ReportCache"
            if (Test-Path $reportCacheDir) {
                Write-Host "  [IMMEDIATE CHECK] Checking ReportCache directory: $reportCacheDir"
                $cacheFiles = Get-ChildItem -Path $reportCacheDir -Filter "*.xlsx" -ErrorAction SilentlyContinue
                if ($cacheFiles) {
                    Write-Host "  [IMMEDIATE CHECK] ✓ Found Excel file(s) in ReportCache:"
                    foreach ($file in $cacheFiles) {
                        Write-Host "    - $($file.FullName) ($([math]::Round($file.Length/1MB, 2)) MB)"
                    }
                } else {
                    Write-Host "  [IMMEDIATE CHECK] ReportCache contents:"
                    $allCacheFiles = Get-ChildItem -Path $reportCacheDir -ErrorAction SilentlyContinue | Select-Object -First 10
                    foreach ($file in $allCacheFiles) {
                        Write-Host "    - $($file.Name) ($($file.Length) bytes)"
                    }
                }
            }

            # Wait a moment for file system to sync (file might still be writing)
            Write-Host "  Waiting 2 seconds for file system to sync..."
            Start-Sleep -Seconds 2

            # Check again after delay
            Write-Host "  [AFTER DELAY CHECK] Checking again after delay..."
            $afterDelayCheck = Get-ChildItem -Path $ariOutputDir -Filter "*.xlsx" -ErrorAction SilentlyContinue -Recurse
            if ($afterDelayCheck) {
                Write-Host "  [AFTER DELAY CHECK] ✓ Found Excel file(s) after delay:"
                foreach ($file in $afterDelayCheck) {
                    Write-Host "    - $($file.FullName) ($([math]::Round($file.Length/1MB, 2)) MB)"
                }
            } else {
                Write-Host "  [AFTER DELAY CHECK] ⚠ No Excel files found after delay - file may have been deleted"
            }

            # Also check if ARI output mentioned a file path
            $filePathHints = $ariOutput | Where-Object { $_ -match '\.xlsx|Excel|Report.*saved|File.*created|saved.*to|created.*at' }
            if ($filePathHints) {
                Write-Host "  File path hints found in ARI output:"
                foreach ($hint in $filePathHints) {
                    Write-Host "    - $hint"
                }
            }
        }

    } catch {
        Write-Host "`n✗ Invoke-ARI threw an exception: $_" -ForegroundColor Red
        Write-Host "  Exception type: $($_.Exception.GetType().FullName)"
        Write-Host "  Stack trace: $($_.ScriptStackTrace)"
        throw
    }

    # Check for Excel file

