    $ErrorActionPreference = 'Continue'

    # Enable Debug to see detailed output (like GitLab shows "Starting to Build Excel Report")
    # This will help us see if Excel building phase starts
    $ariParams.Add("Debug", $true)  # Enable debug to see Excel building phase

    # Run ARI - capture output to see if processing phase runs
    # Use 2>&1 to capture both stdout and stderr so we can see any errors
    Write-Host "`nExecuting Invoke-ARI..."
    Write-Host "Note: Processing phase should start after Extraction Phase Finished"
    Write-Host "If you don't see 'Processing Phase Finished', check for errors below..."
    Write-Host ""

    try {
        # Capture output to see what's happening
        $ariOutput = Invoke-ARI @ariParams 2>&1

        # Write all output so we can see what happened
        # Also capture file path from ARI debug output
        $excelFilePathFromDebug = $null
        $foundFilePaths = @()
        foreach ($line in $ariOutput) {
            if ($line -is [System.Management.Automation.ErrorRecord]) {
                $errMsg = $line.ToString()
                # Don't suppress errors - we need to see what's preventing processing
                Write-Host "ERROR: $errMsg" -ForegroundColor Red
            } else {
                Write-Host $line
                # Look for the debug line that shows the Excel file path
                # Format: "DEBUG: ... - Excel file: /path/to/file.xlsx"
                if ($line -match 'DEBUG.*Excel file:\s*(.+\.xlsx)') {
                    $excelFilePathFromDebug = $matches[1]
                    Write-Host "`n[FOUND] Excel file path from ARI debug output: $excelFilePathFromDebug" -ForegroundColor Green
                }
                # Also look for other file path hints
                if ($line -match '\.xlsx|Excel.*file|Report.*saved|File.*created|saved.*to|created.*at') {
                    $foundFilePaths += $line
                }
            }
        }

        # If we found the file path in debug output, verify it exists IMMEDIATELY
        # This is critical - check right away before any cleanup happens
        if ($excelFilePathFromDebug) {
            Write-Host "`n[IMMEDIATE CHECK] Checking file from debug output: $excelFilePathFromDebug"
            if (Test-Path $excelFilePathFromDebug) {
                Write-Host "`n✓ VERIFIED: Excel file exists at: $excelFilePathFromDebug" -ForegroundColor Green
                $fileInfo = Get-Item $excelFilePathFromDebug
                Write-Host "  File size: $([math]::Round($fileInfo.Length/1MB, 2)) MB"
                Write-Host "  Last modified: $($fileInfo.LastWriteTime)"
                Write-Host "EXCEL_FILE_PATH=$excelFilePathFromDebug"

                # Store the file path in a script-level variable so we can access it later
                $script:FoundExcelFilePath = $excelFilePathFromDebug

                # Also copy to a safe location immediately to prevent loss
                $safeCopyPath = "/root/AzureResourceInventory_SAFE_COPY.xlsx"
                try {
                    Copy-Item -Path $excelFilePathFromDebug -Destination $safeCopyPath -Force -ErrorAction Stop
                    Write-Host "  ✓ Copied to safe location: $safeCopyPath" -ForegroundColor Green
                    Write-Host "SAFE_COPY_PATH=$safeCopyPath"
                } catch {
                    Write-Host "  ⚠ Failed to create safe copy: $_" -ForegroundColor Yellow
                }
            } else {
                Write-Host "`n⚠ WARNING: ARI reported file path but file doesn't exist: $excelFilePathFromDebug" -ForegroundColor Yellow
                Write-Host "  This suggests the file was deleted or never created."
            }
        }

        # If we found file path hints in output, log them
        if ($foundFilePaths.Count -gt 0) {
            Write-Host "`n[DEBUG] Found potential file path hints in ARI output:"
            foreach ($hint in $foundFilePaths) {
                Write-Host "  - $hint"
            }
        }

        Write-Host "`n✓ Invoke-ARI completed"
        Write-Host "[DEBUG] ARI output captured, checking for processing phase completion..."

        # Check if processing phase completed
        $processingFinished = $ariOutput | Where-Object { $_ -match 'Processing Phase Finished' }
        if (-not $processingFinished) {
            Write-Host "`n⚠ WARNING: Processing Phase Finished not detected!"
            Write-Host "  This means the Excel file was NOT generated."
            Write-Host "  Checking for errors that prevented processing..."

            $errors = $ariOutput | Where-Object { $_ -is [System.Management.Automation.ErrorRecord] }
            if ($errors) {
                Write-Host "  Found errors during execution:"
                foreach ($err in $errors) {
                    $errMsg = $err.ToString()
                    if ($errMsg -notmatch 'sigprocmask|unshare|Auto-fitting|Cannot Autosize') {
                        Write-Host "    - $errMsg" -ForegroundColor Red
                    }
                }
            } else {
                Write-Host "  No errors detected, but processing phase didn't complete."
                Write-Host "  This might be a Windmill sandbox limitation."
            }
        } else {
            Write-Host "`n✓ Processing Phase Finished detected - Excel file should be generated"

            # CRITICAL: Check for file IMMEDIATELY after processing finishes
            # Don't wait - check right away in case file gets deleted
            Write-Host "  [IMMEDIATE CHECK] Searching for Excel file RIGHT NOW (before any delays)..."
            $immediateCheck = Get-ChildItem -Path $ariOutputDir -Filter "*.xlsx" -ErrorAction SilentlyContinue -Recurse
            if ($immediateCheck) {
                Write-Host "  [IMMEDIATE CHECK] ✓ Found Excel file(s) immediately:"
                foreach ($file in $immediateCheck) {
                    Write-Host "    - $($file.FullName) ($([math]::Round($file.Length/1MB, 2)) MB)"
                }
            } else {
                Write-Host "  [IMMEDIATE CHECK] ⚠ No Excel files found immediately after Processing Phase Finished"
            }

            # Also check ReportCache directory - ARI might store files there temporarily
            $reportCacheDir = Join-Path $ariOutputDir "ReportCache"
            if (Test-Path $reportCacheDir) {
                Write-Host "  [IMMEDIATE CHECK] Checking ReportCache directory: $reportCacheDir"
                $cacheFiles = Get-ChildItem -Path $reportCacheDir -Filter "*.xlsx" -ErrorAction SilentlyContinue
                if ($cacheFiles) {
                    Write-Host "  [IMMEDIATE CHECK] ✓ Found Excel file(s) in ReportCache:"
                    foreach ($file in $cacheFiles) {
                        Write-Host "    - $($file.FullName) ($([math]::Round($file.Length/1MB, 2)) MB)"
                    }
                } else {
                    Write-Host "  [IMMEDIATE CHECK] ReportCache contents:"
                    $allCacheFiles = Get-ChildItem -Path $reportCacheDir -ErrorAction SilentlyContinue | Select-Object -First 10
                    foreach ($file in $allCacheFiles) {
                        Write-Host "    - $($file.Name) ($($file.Length) bytes)"
                    }
                }
            }

            # Wait a moment for file system to sync (file might still be writing)
            Write-Host "  Waiting 2 seconds for file system to sync..."
            Start-Sleep -Seconds 2

            # Check again after delay
            Write-Host "  [AFTER DELAY CHECK] Checking again after delay..."
            $afterDelayCheck = Get-ChildItem -Path $ariOutputDir -Filter "*.xlsx" -ErrorAction SilentlyContinue -Recurse
            if ($afterDelayCheck) {
                Write-Host "  [AFTER DELAY CHECK] ✓ Found Excel file(s) after delay:"
                foreach ($file in $afterDelayCheck) {
                    Write-Host "    - $($file.FullName) ($([math]::Round($file.Length/1MB, 2)) MB)"
                }
            } else {
                Write-Host "  [AFTER DELAY CHECK] ⚠ No Excel files found after delay - file may have been deleted"
            }

            # Also check if ARI output mentioned a file path
            $filePathHints = $ariOutput | Where-Object { $_ -match '\.xlsx|Excel|Report.*saved|File.*created|saved.*to|created.*at' }
            if ($filePathHints) {
                Write-Host "  File path hints found in ARI output:"
                foreach ($hint in $filePathHints) {
                    Write-Host "    - $hint"
                }
            }
        }

    } catch {
        Write-Host "`n✗ Invoke-ARI threw an exception: $_" -ForegroundColor Red
        Write-Host "  Exception type: $($_.Exception.GetType().FullName)"
        Write-Host "  Stack trace: $($_.ScriptStackTrace)"
        throw
    }

    # Check for Excel file in multiple locations - CRITICAL: This must run before script exits
    Write-Host ""
    Write-Host "========================================"
    Write-Host "POWERSHELL FILE SEARCH STARTING"
    Write-Host "========================================"
    $excelFile = $null
    $currentDir = (Get-Location).Path
    Write-Host "Current working directory: $currentDir"
    Write-Host "Report name: $reportName"
    Write-Host "Expected filename: $reportName.xlsx"
    Write-Host "HOME directory: $env:HOME"
    Write-Host "ARI Output Dir: $ariOutputDir"

    $searchPaths = @(
        $currentDir,  # Current working directory (where PowerShell is running - most likely location)
        $ariOutputDir,  # Explicitly set ARI output directory (/root/AzureResourceInventory)
        "/root",  # Root directory
        "$env:HOME/AzureResourceInventory",  # ARI's default location on Linux ($HOME/AzureResourceInventory)
        $env:HOME,  # Home directory itself
        "/root/.local/share/powershell/Modules/AzureResourceInventory",  # Module installation directory (ARI might create files here)
        "$env:HOME/.local/share/powershell/Modules/AzureResourceInventory"  # Alternative module path
    )

    Write-Host "[POWERSHELL] Checking paths (in order):"
    foreach ($searchPath in $searchPaths) {
        if (-not $searchPath) { continue }
        Write-Host "[POWERSHELL]   Checking: $searchPath"

        if (-not (Test-Path $searchPath)) {
            Write-Host "[POWERSHELL]     (path does not exist)"
            continue
        }

        # Look for file with exact ReportName (recursive search)
        Write-Host "[POWERSHELL]     Looking for: $reportName.xlsx (recursive)"
        $file = Get-ChildItem -Path $searchPath -Filter "$reportName.xlsx" -ErrorAction SilentlyContinue -Recurse
        if ($file) {
            $excelFile = $file
            Write-Host "[POWERSHELL]     ✓ FOUND: $($file.FullName) ($([math]::Round($file.Length/1MB, 2)) MB)"
            Write-Host "EXCEL_FILE_PATH=$($file.FullName)"
            break
        }

        # Look for files matching the pattern (ARI might append ReportName to default name)
        Write-Host "[POWERSHELL]     Looking for files matching pattern: *$reportName*.xlsx (recursive)"
        $patternFiles = Get-ChildItem -Path $searchPath -Filter "*$reportName*.xlsx" -ErrorAction SilentlyContinue -Recurse
        if ($patternFiles) {
            $excelFile = $patternFiles | Sort-Object LastWriteTime -Descending | Select-Object -First 1
            Write-Host "[POWERSHELL]     ✓ FOUND pattern match: $($excelFile.Name) ($([math]::Round($excelFile.Length/1MB, 2)) MB) at $($excelFile.FullName)"
            Write-Host "EXCEL_FILE_PATH=$($excelFile.FullName)"
            break
        }

        # Look for any .xlsx files created recently (within last 5 minutes) - RECURSIVE search
        Write-Host "[POWERSHELL]     Looking for any recent .xlsx files (recursive)..."
        $allExcelFiles = Get-ChildItem -Path $searchPath -Filter "*.xlsx" -ErrorAction SilentlyContinue -Recurse | 
            Where-Object { $_.LastWriteTime -gt (Get-Date).AddMinutes(-5) }
        if ($allExcelFiles) {
            $excelFile = $allExcelFiles | Sort-Object LastWriteTime -Descending | Select-Object -First 1
            Write-Host "[POWERSHELL]     ✓ FOUND recent Excel file: $($excelFile.Name) ($([math]::Round($excelFile.Length/1MB, 2)) MB) at $($excelFile.FullName)"
            Write-Host "EXCEL_FILE_PATH=$($excelFile.FullName)"
            break
        } else {
            Write-Host "[POWERSHELL]     No recent .xlsx files found"
        }
    }

    if (-not $excelFile) {
        Write-Host "[POWERSHELL]   ⚠ Excel file not found in any of the searched locations"
        Write-Host "[POWERSHELL]   Listing contents of key directories:"
        Write-Host "[POWERSHELL]     Current directory ($currentDir):"
        if (Test-Path $currentDir) {
            $currentFiles = Get-ChildItem -Path $currentDir -ErrorAction SilentlyContinue | Select-Object -First 20
            foreach ($file in $currentFiles) {
                Write-Host "[POWERSHELL]       - $($file.Name) ($($file.Length) bytes, modified: $($file.LastWriteTime))"
            }
        }
        Write-Host "[POWERSHELL]     ARI output directory ($ariOutputDir):"
        if (Test-Path $ariOutputDir) {
            $ariFiles = Get-ChildItem -Path $ariOutputDir -ErrorAction SilentlyContinue
            foreach ($file in $ariFiles) {
                Write-Host "[POWERSHELL]       - $($file.Name) ($($file.Length) bytes, modified: $($file.LastWriteTime))"
            }
        }
    } else {
        Write-Host "[POWERSHELL]   ✓ Excel file located successfully at: $($excelFile.FullName)"
    }

    # Mark as successful if we got here (Invoke-ARI completed without throwing)
    $ariSuccess = $true
    $script:ScriptSuccess = $true
    Write-Host "`n✓ ARI execution completed successfully"

} catch {
    # Check if it's the known Windmill sandbox error
    $errorMsg = $_.ToString()
    if ($errorMsg -match 'sigprocmask|unshare') {
        Write-Host "`n⚠ Windmill sandbox warning (ignored): $errorMsg" -ForegroundColor Yellow
        Write-Host "The script completed successfully despite this sandbox limitation."
        $ariSuccess = $true
        $script:ScriptSuccess = $true
    } else {
        Write-Host "`n✗ ARI execution failed: $_" -ForegroundColor Red
        $ariSuccess = $false
        $script:ScriptSuccess = $false
        throw
    }
} finally {
    # Restore error action preference, but suppress sandbox errors
    $ErrorActionPreference = 'SilentlyContinue'
}

Write-Host "`n========================================"
Write-Host " Script Completed"
Write-Host "========================================"
Write-Host ""
Write-Host "Note: If you see 'sigprocmask unblock failed' errors, these are"
Write-Host "Windmill sandbox limitations and can be safely ignored if the"
Write-Host "script completed successfully."
Write-Host ""

# Store success state before any cleanup
$finalSuccess = $script:ScriptSuccess -or $ariSuccess

# CRITICAL: Remove all Azure modules BEFORE exit to prevent sigprocmask errors
# The sigprocmask error occurs when PowerShell tries to clean up modules during exit
# By removing them explicitly, we avoid triggering the error
Write-Verbose "Removing modules to prevent cleanup errors..." -Verbose:$false
$ErrorActionPreference = 'SilentlyContinue'
try {
    # Get all Azure-related modules
    $modulesToRemove = Get-Module | Where-Object { 
        $_.Name -like 'Az*' -or 
        $_.Name -eq 'AzureResourceInventory' -or
        $_.Name -like 'Microsoft.Azure*'
    }

    if ($modulesToRemove) {
        foreach ($module in $modulesToRemove) {
            Remove-Module -Name $module.Name -Force -ErrorAction SilentlyContinue | Out-Null
        }
        # Wait for cleanup to complete
        Start-Sleep -Seconds 1
    }
} catch {
    # Ignore any cleanup errors - we're about to exit anyway
}

# Clear error variables to prevent any errors from propagating
$Error.Clear()
$ErrorActionPreference = 'SilentlyContinue'
$PSDefaultParameterValues['*:ErrorAction'] = 'SilentlyContinue'

# Write success marker to stdout BEFORE exit
# This helps Windmill detect success even if stderr has the sigprocmask error
if ($finalSuccess) {
    Write-Output "SCRIPT_SUCCESS=true"
    Write-Output "ARI_EXTRACTION_COMPLETED=true"
}

# Use .NET Exit method to bypass PowerShell's cleanup handlers entirely
# This prevents PowerShell from trying to clean up modules (which triggers sigprocmask error)
if ($finalSuccess) {
    # Exit immediately without PowerShell cleanup
    [System.Environment]::Exit(0)
} else {
    [System.Environment]::Exit(1)
}
'''

def filter_sandbox_errors(stderr_text):
    """
    Filter out known Windmill sandbox errors from stderr.

    Windmill uses nsjail to sandbox scripts, which can produce harmless system-level
    errors like 'sigprocmask unblock failed'. These errors don't indicate actual script
    failures and should be filtered out to avoid confusion.

    Args:
        stderr_text: Raw stderr output from PowerShell script

    Returns:
        Filtered stderr text with sandbox errors removed
    """
    # Define patterns for known Windmill sandbox errors
    sandbox_patterns = [
        r'sigprocmask',
        r'unshare.*unblock failed',
        r'unshare:.*Invalid argument',
        r'unshare: sigprocmask unblock failed'
    ]

    # Filter out lines matching sandbox error patterns
    filtered_lines = []
    for line in stderr_text.split('\n'):
        if line.strip():
            # Check if this line matches any sandbox error pattern
            is_sandbox_error = any(re.search(pattern, line, re.IGNORECASE) for pattern in sandbox_patterns)
            if not is_sandbox_error:
                # Keep non-sandbox errors
                filtered_lines.append(line)

    return '\n'.join(filtered_lines)

def get_memory_info():
    """
    Get current memory usage and limits.
    Returns dict with memory information for monitoring.
    """
    try:
        import psutil
        process = psutil.Process(os.getpid())
        mem_info = process.memory_info()
        current_mb = mem_info.rss / 1024 / 1024

        # Try to get memory limit from cgroup (Linux containers)
        mem_limit_mb = None
        mem_limit_bytes = None
        mem_usage_percent = None

        cgroup_paths = [
            '/sys/fs/cgroup/memory/memory.limit_in_bytes',
            '/sys/fs/cgroup/memory.max',  # cgroup v2
        ]

        for path in cgroup_paths:
            try:
                if os.path.exists(path):
                    with open(path, 'r') as f:
                        limit_str = f.read().strip()
                        # Handle "max" value in cgroup v2
                        if limit_str == 'max':
                            mem_limit_bytes = None
                            mem_limit_mb = None
                        else:
                            mem_limit_bytes = int(limit_str)
                            mem_limit_mb = mem_limit_bytes / 1024 / 1024
                            mem_usage_percent = (mem_info.rss / mem_limit_bytes) * 100
                    break
            except (IOError, ValueError):
                continue

        return {
            'current_mb': current_mb,
            'limit_mb': mem_limit_mb,
            'limit_bytes': mem_limit_bytes,
            'usage_percent': mem_usage_percent,
            'available': True
        }
    except ImportError:
        # psutil not available
        return {
            'current_mb': None,
            'limit_mb': None,
            'limit_bytes': None,
            'usage_percent': None,
            'available': False,
            'note': 'psutil not available - install with: pip install psutil'
        }
    except Exception:
        return {
            'current_mb': None,
            'limit_mb': None,
            'limit_bytes': None,
            'usage_percent': None,
            'available': False,
            'note': 'Memory monitoring not available'
        }

def print_memory_info(label="Memory"):
    """Print formatted memory information"""
    mem_info = get_memory_info()

    if not mem_info['available']:
        print(f"[{label}] Memory monitoring: {mem_info.get('note', 'Not available')}")
        return mem_info

    print(f"[{label}] Current memory usage: {mem_info['current_mb']:.2f} MB")

    if mem_info['limit_mb'] is not None:
        print(f"[{label}] Memory limit: {mem_info['limit_mb']:.2f} MB")
        if mem_info['usage_percent'] is not None:
            print(f"[{label}] Memory usage: {mem_info['usage_percent']:.1f}%")

            # Warn if approaching limit
            if mem_info['usage_percent'] > 90:
                print(f"[{label}] ⚠ WARNING: Memory usage is above 90% - may cause OOM kill")
            elif mem_info['usage_percent'] > 75:
                print(f"[{label}] ⚠ WARNING: Memory usage is above 75% - monitor closely")
    else:
        print(f"[{label}] Memory limit: Not set (unlimited or not in cgroup)")

    return mem_info

def get_windmill_variable(variable_name: str, path_prefix: str = "f/ARI", required: bool = True) -> str:
    """
    Retrieve a Windmill variable using Windmill API.

    Args:
        variable_name: Name of the variable to retrieve
        path_prefix: Path prefix for Windmill variable (default: "f/ARI")
        required: If True, raise error if variable not found

    Returns:
        Variable value as string

    Raises:
        ValueError: If required=True and variable not found
    """
    # Construct the full variable path
    variable_path = f"{path_prefix}/{variable_name}"

    # Get Windmill API credentials from environment variables
    # These are automatically set by Windmill when running scripts
    wm_token = os.getenv("WM_TOKEN")
    base_url = os.getenv("BASE_INTERNAL_URL") or os.getenv("WM_BASE_URL")
    workspace = os.getenv("WM_WORKSPACE")

    # Check if all required environment variables are available
    if not (wm_token and base_url and workspace):
        if required:
            raise ValueError(
                f"Windmill API not available (missing WM_TOKEN, BASE_INTERNAL_URL, or WM_WORKSPACE). "
                f"Cannot retrieve {variable_name} at {variable_path}"
            )
        return ""

    try:
        # Import requests module (required for API calls)
        import requests

        # Construct API URL to retrieve variable value
        api_url = f"{base_url}/api/w/{workspace}/variables/get_value/{variable_path}"
        headers = {"Authorization": f"Bearer {wm_token}"}

        # Make API request to Windmill
        response = requests.get(api_url, headers=headers, timeout=10)

        # Process successful response
        if response.status_code == 200:
            result = response.json()

            # Handle different response formats (dict with 'value' key, or direct string)
            if isinstance(result, dict) and 'value' in result:
                value_str = str(result['value']).strip()
            elif isinstance(result, str):
                value_str = result.strip()
            else:
                value_str = str(result).strip()

            # Return non-empty value
            if value_str:
                print(f"✓ Found {variable_name} via Windmill API at {variable_path}")
                return value_str

        # Variable not found or empty
        if required:
            raise ValueError(
                f"{variable_name} is required but not found at {variable_path}. "
                f"API returned status {response.status_code}"
            )
        return ""

    except ImportError:
        # Handle missing requests module
        if required:
            raise ValueError(
                f"requests module not available. Cannot retrieve {variable_name} at {variable_path}"
            )
        return ""
    except Exception as e:
        # Handle other API errors
        if required:
            raise ValueError(
                f"Failed to retrieve {variable_name} at {variable_path}: {e}"
            )
        return ""

def commit_file_to_gitlab(file_path: str, gitlab_token: str) -> dict:
    """
    Commit Excel file to GitLab repository.
    Hardcoded to commit to 'presidio' branch.

    Args:
        file_path: Path to the Excel file to commit
        gitlab_token: GitLab personal access token

    Returns:
        Dictionary with commit results
    """
    branch_name = "presidio"  # Hardcoded branch name
    repo_path = "/tmp/ari-git-repo"
    repo_url = "https://gitlab.com/presidioms/managed-cloud/ari-git.git"

    try:
        # Clean up any existing repository clone to ensure fresh start
        if os.path.exists(repo_path):
            shutil.rmtree(repo_path)

        # Clone repository using git commands (no GitPython dependency)
        # Uses OAuth2 token authentication embedded in URL
        print(f"\nCloning GitLab repository to {repo_path}...")
        clone_url = f"https://oauth2:{gitlab_token}@gitlab.com/presidioms/managed-cloud/ari-git.git"

        # Try to clone the specific branch first
        clone_cmd = ["git", "clone", "--depth", "1", "--branch", branch_name, clone_url, repo_path]
        result = subprocess.run(clone_cmd, capture_output=True, text=True, timeout=60)

        # If branch doesn't exist, clone default branch and create new branch
        if result.returncode != 0:
            print(f"Branch {branch_name} not found, cloning default branch...")
            clone_cmd = ["git", "clone", "--depth", "1", clone_url, repo_path]
            subprocess.run(clone_cmd, check=True, timeout=60)

            # Create and checkout the new branch
            subprocess.run(["git", "checkout", "-b", branch_name], cwd=repo_path, check=True)

        # Configure git user identity for commits
        # Required for git commit to work
        subprocess.run(["git", "config", "user.name", "Windmill Bot"], cwd=repo_path, check=True)
        subprocess.run(["git", "config", "user.email", "windmill-bot@presidio.com"], cwd=repo_path, check=True)

        # Create AzureResourceInventory directory structure if it doesn't exist
        # This matches the directory structure used in GitLab CI
        ari_dir = os.path.join(repo_path, "AzureResourceInventory")
        os.makedirs(ari_dir, exist_ok=True)

        # Copy the Excel file to the repository directory
        file_name = os.path.basename(file_path)
        dest_path = os.path.join(ari_dir, file_name)
        shutil.copy2(file_path, dest_path)
        print(f"✓ Copied {file_name} to repository")

        # Stage the file for commit
        subprocess.run(["git", "add", f"AzureResourceInventory/{file_name}"], cwd=repo_path, check=True)

        # Create commit with timestamp and [skip ci] tag to prevent triggering CI/CD
        commit_msg = f"ARI report from Windmill - {datetime.now().strftime('%Y-%m-%d %H:%M:%S')} [skip ci]"
        subprocess.run(["git", "commit", "-m", commit_msg], cwd=repo_path, check=True)
        print(f"✓ Committed file to repository")

        # Push the commit to GitLab
        # Uses OAuth2 token in URL for authentication
        push_url = f"https://oauth2:{gitlab_token}@gitlab.com/presidioms/managed-cloud/ari-git.git"
        subprocess.run(["git", "push", push_url, f"HEAD:{branch_name}"], cwd=repo_path, check=True, timeout=60)
        print(f"✓ Pushed to GitLab branch: {branch_name}")

        return {
            "status": "success",
            "file_committed": file_name,
            "branch": branch_name,
            "commit_message": commit_msg
        }

    except subprocess.TimeoutExpired:
        print(f"⚠ GitLab operation timed out")
        return {
            "status": "error",
            "error": "Operation timed out"
        }
    except subprocess.CalledProcessError as e:
        print(f"⚠ GitLab commit failed: {e}")
        if e.stdout:
            print(f"  stdout: {e.stdout}")
        if e.stderr:
            print(f"  stderr: {e.stderr}")
        return {
            "status": "error",
            "error": str(e)
        }
    except Exception as e:
        print(f"⚠ GitLab commit failed: {e}")
        return {
            "status": "error",
            "error": str(e)
        }
    finally:
        # Cleanup
        if os.path.exists(repo_path):
            try:
                shutil.rmtree(repo_path)
            except:
                pass


def main(
