):
    """
    Run PowerShell ARI script and handle sigprocmask errors.
    Automatically retrieves GitLab token from Windmill variable f/ARI/BSPILKER_GITLAB_TOKEN.

    Args:
        tenantid: Azure Tenant ID (default: 30759d1a-f690-4205-9005-7d871a4f484c)
        subscription_ids: Comma-separated subscription IDs (default: 97c4ecbb-e54d-4bc1-bfc5-32cc73c03bee,d4f0b259-e982-48f7-9953-fb07adec333c)
        client_id: Service Principal Client ID (required)
        client_secret: Service Principal Secret (required)

    Returns:
        Dictionary with execution results
    """
    # ============================================================================
    # PARAMETER VALIDATION AND SETUP
    # ============================================================================

    # Validate that required Azure service principal credentials are provided
    if not client_id or not client_secret:
        raise ValueError("client_id and client_secret are required")

    # Use defaults if empty strings are passed (Windmill may pass empty strings for optional params)
    # This handles cases where Windmill UI passes empty strings instead of omitting parameters
    if not tenantid or tenantid.strip() == '':
        tenantid = '30759d1a-f690-4205-9005-7d871a4f484c'
    if not subscription_ids or subscription_ids.strip() == '':
        subscription_ids = '97c4ecbb-e54d-4bc1-bfc5-32cc73c03bee,d4f0b259-e982-48f7-9953-fb07adec333c'

    # ============================================================================
    # GITLAB TOKEN RETRIEVAL
    # ============================================================================

    # Retrieve GitLab token from Windmill variable (optional - script will work without it)
    # If token is not available, the script will still run but won't commit files to GitLab
    gitlab_token = None
    try:
        gitlab_token = get_windmill_variable("BSPILKER_GITLAB_TOKEN", required=False)
        if not gitlab_token:
            print(f"⚠ GitLab token not found - file will not be committed to GitLab")
    except Exception as e:
        print(f"⚠ Could not retrieve GitLab token: {e}")
        print(f"  File will not be committed to GitLab, but ARI will still run")

    # ============================================================================
    # POWERSHELL SCRIPT PREPARATION
    # ============================================================================

    # Check initial memory state
    print("\n[MEMORY] Initial memory check:")
    initial_mem = print_memory_info("INITIAL")
