        # 3. Log rotation may trigger at certain intervals (often coincides with step timeout)
        # 
        # The inconsistency (4 min vs 14 min) suggests:
        # - Different workers may have different timeout configurations
        # - Per-step timeout (4 min) is being enforced in some cases
        # - Total script timeout (14 min) may apply in other cases
        # - Resource availability (memory/CPU) may affect when kill happens
        if exit_code == -9:
            # Check for log rotation message in output (indicates step timeout)
            log_rotation_detected = any('[windmill] Previous logs have been saved' in line for line in stdout_lines)

            if 235 <= elapsed_time <= 245:  # Exactly 4 minutes (240 seconds)
