            elif 800 <= elapsed_time <= 900:
                print(f"[WAITING] ⚠ Timeout detected: ~{elapsed_time:.0f} seconds (~{elapsed_minutes}m {elapsed_seconds}s)")
                print(f"[WAITING] This suggests Windmill has a ~14 minute timeout limit")
                print(f"[WAITING] NOTE: Different from 4-minute timeout - may be different worker/config")
                print(f"[WAITING] This could be total script timeout rather than per-step timeout")
            else:
                print(f"[WAITING] ⚠ Process killed after {elapsed_time:.0f} seconds (~{elapsed_minutes}m {elapsed_seconds}s)")
                print(f"[WAITING] This may indicate a variable timeout or resource limit")
                print(f"[WAITING] Inconsistent timeouts suggest different worker configurations or timeout layers")

            # General recommendations
            print(f"\n[WAITING] RECOMMENDATIONS:")
