                    print(f"   Memory limit is {after_mem['limit_mb']:.2f} MB (< 2GB)")
                    print("   This may be insufficient for ARI processing phase")
                    print("")

            print("The processing phase was interrupted before it could complete.")
            print("Excel file generation happens during processing phase, so the file was never created.")
            print("")
            print("SOLUTIONS:")
            print("  1. Check Windmill script timeout settings - increase if possible")
