            $excelFile = $patternFiles | Sort-Object LastWriteTime -Descending | Select-Object -First 1
            Write-Host "[POWERSHELL]     ✓ FOUND pattern match: $($excelFile.Name) ($([math]::Round($excelFile.Length/1MB, 2)) MB) at $($excelFile.FullName)"
            Write-Host "EXCEL_FILE_PATH=$($excelFile.FullName)"
            break
        }

        # Look for any .xlsx files created recently (within last 5 minutes) - RECURSIVE search
        Write-Host "[POWERSHELL]     Looking for any recent .xlsx files (recursive)..."
        $allExcelFiles = Get-ChildItem -Path $searchPath -Filter "*.xlsx" -ErrorAction SilentlyContinue -Recurse | 
            Where-Object { $_.LastWriteTime -gt (Get-Date).AddMinutes(-5) }
        if ($allExcelFiles) {
            $excelFile = $allExcelFiles | Sort-Object LastWriteTime -Descending | Select-Object -First 1
            Write-Host "[POWERSHELL]     ✓ FOUND recent Excel file: $($excelFile.Name) ($([math]::Round($excelFile.Length/1MB, 2)) MB) at $($excelFile.FullName)"
            Write-Host "EXCEL_FILE_PATH=$($excelFile.FullName)"
            break
        } else {
            Write-Host "[POWERSHELL]     No recent .xlsx files found"
        }
    }

    if (-not $excelFile) {
        Write-Host "[POWERSHELL]   ⚠ Excel file not found in any of the searched locations"
        Write-Host "[POWERSHELL]   Listing contents of key directories:"
        Write-Host "[POWERSHELL]     Current directory ($currentDir):"
        if (Test-Path $currentDir) {
            $currentFiles = Get-ChildItem -Path $currentDir -ErrorAction SilentlyContinue | Select-Object -First 20
            foreach ($file in $currentFiles) {
                Write-Host "[POWERSHELL]       - $($file.Name) ($($file.Length) bytes, modified: $($file.LastWriteTime))"
            }
        }
        Write-Host "[POWERSHELL]     ARI output directory ($ariOutputDir):"
        if (Test-Path $ariOutputDir) {
            $ariFiles = Get-ChildItem -Path $ariOutputDir -ErrorAction SilentlyContinue
            foreach ($file in $ariFiles) {
                Write-Host "[POWERSHELL]       - $($file.Name) ($($file.Length) bytes, modified: $($file.LastWriteTime))"
            }
        }
    } else {
        Write-Host "[POWERSHELL]   ✓ Excel file located successfully at: $($excelFile.FullName)"
    }

    # Mark as successful if we got here (Invoke-ARI completed without throwing)
    $ariSuccess = $true
    $script:ScriptSuccess = $true
    Write-Host "`n✓ ARI execution completed successfully"

} catch {
    # Check if it's the known Windmill sandbox error
    $errorMsg = $_.ToString()
    if ($errorMsg -match 'sigprocmask|unshare') {
        Write-Host "`n⚠ Windmill sandbox warning (ignored): $errorMsg" -ForegroundColor Yellow
        Write-Host "The script completed successfully despite this sandbox limitation."
        $ariSuccess = $true
        $script:ScriptSuccess = $true
    } else {
        Write-Host "`n✗ ARI execution failed: $_" -ForegroundColor Red
        $ariSuccess = $false
        $script:ScriptSuccess = $false
        throw
    }
} finally {
    # Restore error action preference, but suppress sandbox errors
    $ErrorActionPreference = 'SilentlyContinue'
}

Write-Host "`n========================================"
Write-Host " Script Completed"
Write-Host "========================================"
Write-Host ""
Write-Host "Note: If you see 'sigprocmask unblock failed' errors, these are"
Write-Host "Windmill sandbox limitations and can be safely ignored if the"
Write-Host "script completed successfully."
Write-Host ""

# Store success state before any cleanup
$finalSuccess = $script:ScriptSuccess -or $ariSuccess

# CRITICAL: Remove all Azure modules BEFORE exit to prevent sigprocmask errors
# The sigprocmask error occurs when PowerShell tries to clean up modules during exit
# By removing them explicitly, we avoid triggering the error
Write-Verbose "Removing modules to prevent cleanup errors..." -Verbose:$false
$ErrorActionPreference = 'SilentlyContinue'
try {
    # Get all Azure-related modules
    $modulesToRemove = Get-Module | Where-Object { 
        $_.Name -like 'Az*' -or 
        $_.Name -eq 'AzureResourceInventory' -or
        $_.Name -like 'Microsoft.Azure*'
    }

    if ($modulesToRemove) {
        foreach ($module in $modulesToRemove) {
            Remove-Module -Name $module.Name -Force -ErrorAction SilentlyContinue | Out-Null
        }
        # Wait for cleanup to complete
        Start-Sleep -Seconds 1
    }
} catch {
    # Ignore any cleanup errors - we're about to exit anyway
}

# Clear error variables to prevent any errors from propagating
$Error.Clear()
$ErrorActionPreference = 'SilentlyContinue'
$PSDefaultParameterValues['*:ErrorAction'] = 'SilentlyContinue'

# Write success marker to stdout BEFORE exit
# This helps Windmill detect success even if stderr has the sigprocmask error
if ($finalSuccess) {
    Write-Output "SCRIPT_SUCCESS=true"
    Write-Output "ARI_EXTRACTION_COMPLETED=true"
}

# Use .NET Exit method to bypass PowerShell's cleanup handlers entirely
# This prevents PowerShell from trying to clean up modules (which triggers sigprocmask error)
if ($finalSuccess) {
    # Exit immediately without PowerShell cleanup
    [System.Environment]::Exit(0)
} else {
    [System.Environment]::Exit(1)
}
