    print("")

    # Check initial memory state
    print("\n[MEMORY] Initial memory check:")
    initial_mem = print_memory_info("INITIAL")
    print("")

    # Create temporary PowerShell script file from embedded content
    # The PowerShell script is embedded as a string constant in this Python file
    # We write it to a temporary file so PowerShell can execute it
    with tempfile.NamedTemporaryFile(mode='w', suffix='.ps1', delete=False) as f:
        f.write(POWERSHELL_SCRIPT)
        script_path = f.name

    try:
