            '-client_id', client_id,
            '-client_secret', client_secret
        ]

        # Construct full PowerShell command: pwsh -File <script> <args>
        pwsh_cmd = ['pwsh', '-File', script_path] + pwsh_args

        # ========================================================================
        # EXECUTE POWERSHELL SCRIPT WITH LINE-BY-LINE OUTPUT PROCESSING
        # ========================================================================

        # Run PowerShell script and process output line-by-line to catch file immediately
        # Using line-by-line processing allows us to detect and capture the Excel file
        # as soon as ARI reports its location, before it might be deleted
        import time as time_module
        process_start_time = time_module.time()  # Start timing when process launches

        # Check memory before starting PowerShell
        print("[MEMORY] Before PowerShell execution:")
        before_pwsh_mem = print_memory_info("BEFORE_PWSH")
        print("")

        process = subprocess.Popen(
            pwsh_cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            bufsize=1  # Line buffered for real-time processing
        )

        # Initialize variables for output collection and file tracking
        stdout_lines = []
        stderr_lines = []
        excel_file_path_from_output = None
        file_captured = False

        # ========================================================================
        # PROCESS STDOUT LINE-BY-LINE (REAL-TIME FILE CAPTURE)
        # ========================================================================

        # Read stdout line by line as it's produced
        # This allows us to react immediately when ARI reports the Excel file path
        for line in process.stdout:
            # Store line for later processing
            stdout_lines.append(line)
            # Print line immediately so user sees progress
            print(line, end='')

            # Look for Excel file path in debug output IMMEDIATELY
            # ARI outputs: "DEBUG: ... - Excel file: /path/to/file.xlsx"
            # NOTE: ARI reports the path BEFORE creating the file, so we need to wait and retry
            if not file_captured and 'DEBUG' in line and 'Excel file:' in line:
                import re
                # Extract file path from debug output using regex
                debug_pattern = r'DEBUG.*Excel file:\s*(.+\.xlsx)'
                debug_match = re.search(debug_pattern, line)
                if debug_match:
                    excel_file_path_from_output = debug_match.group(1).strip()
                    print(f"\n[IMMEDIATE] Found Excel file path: {excel_file_path_from_output}")
                    print(f"[IMMEDIATE] Note: ARI reports path before creating file, will check after processing completes")

            # Look for "Processing Phase Finished" - file should exist by then
            # This is when ARI actually completes Excel file generation
            # IMPORTANT: Don't match the warning message "If you don't see 'Processing Phase Finished'"
            if not file_captured and 'Processing Phase Finished' in line and 'If you don\'t see' not in line:
                print(f"\n[AFTER PROCESSING] Processing Phase Finished detected - checking for Excel file...")

                # Wait a moment for file system to sync (file might still be writing)
                time.sleep(3)

                # Check if we have a file path to check
                if excel_file_path_from_output:
                    print(f"[AFTER PROCESSING] Checking reported path: {excel_file_path_from_output}")
