                                    except Exception as e:
                                        print(f"[AFTER PROCESSING] ⚠ Failed to copy/commit: {e}")
                                    break
                            else:
                                print(f"[AFTER PROCESSING]   ReportCache directory exists but contains no .xlsx files")
                                # List what's actually in ReportCache
