                print("   Found Excel-related messages:")
                for msg in excel_messages[-20:]:  # Last 20 messages
                    print(f"     - {msg.strip()}")
            else:
                print("   No Excel-related messages found")

            # Check processing phase completion
            print("\n3. Processing Phase Analysis:")
            processing_lines = [i for i, line in enumerate(stdout_lines) if 'Processing Phase' in line]
            if processing_lines:
                print(f"   Found {len(processing_lines)} 'Processing Phase' mentions:")
                for idx in processing_lines[-5:]:  # Last 5 mentions
                    context_start = max(0, idx - 2)
                    context_end = min(len(stdout_lines), idx + 3)
                    print(f"     Line {idx}:")
                    for i in range(context_start, context_end):
                        marker = ">>> " if i == idx else "    "
                        print(f"     {marker}{stdout_lines[i].strip()}")
            else:
                print("   No 'Processing Phase' mentions found")

            # Check for any errors that might have prevented file creation
            print("\n4. Error Analysis:")
            error_lines = [
                (i, line) for i, line in enumerate(stdout_lines)
                if any(keyword in line.lower() for keyword in ['error', 'failed', 'exception', 'cannot', 'unable'])
